"""Динамический редактор параметров + ScientificDoubleSpinBox."""from __future__ import annotationsimport mathimport refrom typing import Anyfrom PySide6.QtGui import QValidatorfrom PySide6.QtWidgets import (    QAbstractSpinBox, QCheckBox, QComboBox, QDoubleSpinBox, QFormLayout,    QLabel, QSpinBox, QWidget,)_SCI_LOW = 1.0e-3_SCI_HIGH = 1.0e6_SIG_DIGITS = 12_SCI_PATTERN = re.compile(    r"^\s*[-+]?(\d+(\.\d*)?|\.\d+)([eE][-+]?\d+)?\s*$")def _format_value(v: float) -> str:    if v == 0.0 or not math.isfinite(v):        return "0"    av = abs(v)    if av < _SCI_LOW or av >= _SCI_HIGH:        return f"{v:.6g}"    return f"{v:.{_SIG_DIGITS}g}"class ScientificDoubleSpinBox(QDoubleSpinBox):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__(parent)        super().setDecimals(_SIG_DIGITS)        self.setKeyboardTracking(False)        self.setButtonSymbols(QAbstractSpinBox.UpDownArrows)    def validate(self, text: str, pos: int) -> tuple[QValidator.State, str, int]:        if text.strip() in ("", "-", "+", ".", "-.", "+."):            return QValidator.Intermediate, text, pos        if _SCI_PATTERN.match(text):            try:                float(text)                return QValidator.Acceptable, text, pos            except ValueError:                return QValidator.Intermediate, text, pos        return QValidator.Invalid, text, pos    def valueFromText(self, text: str) -> float:        try:            return float(text)        except (TypeError, ValueError):            return self.value()    def textFromValue(self, value: float) -> str:        return _format_value(value)    def stepBy(self, steps: int) -> None:        v = self.value()        av = abs(v)        if av == 0.0:            step = max(abs(self.singleStep()), 1.0e-12)        else:            step = max(av * 0.1, 1.0e-12)        new = v + steps * step        new = min(max(new, self.minimum()), self.maximum())        self.setValue(new)_FLOAT_DEFAULT_MIN = -1.0e12_FLOAT_DEFAULT_MAX = 1.0e12class ParamsEditor(QWidget):    def __init__(self, schema: dict[str, dict[str, Any]] | None = None,                 parent: QWidget | None = None) -> None:        super().__init__(parent)        self._form = QFormLayout(self)        self._form.setContentsMargins(0, 0, 0, 0)        self._form.setFieldGrowthPolicy(QFormLayout.AllNonFixedFieldsGrow)        self._widgets: dict[str, QWidget] = {}        self._schema: dict[str, dict[str, Any]] = {}        if schema:            self.set_schema(schema)    def set_schema(self, schema: dict[str, dict[str, Any]]) -> None:        self._clear()        self._schema = dict(schema)        for key, spec in schema.items():            widget = self._build_widget(spec)            label_text = spec.get("label", key)            units = spec.get("units")            if units:                label_text = f"{label_text} ({units})"            label = QLabel(label_text)            tooltip = spec.get("description")            if tooltip:                widget.setToolTip(tooltip)                label.setToolTip(tooltip)            self._form.addRow(label, widget)            self._widgets[key] = widget    def _clear(self) -> None:        while self._form.rowCount() > 0:            self._form.removeRow(0)        self._widgets.clear()        self._schema = {}    def _build_widget(self, spec: dict[str, Any]) -> QWidget:        t = spec["type"]        default = spec["default"]        if t == "int":            w_int = QSpinBox()            w_int.setRange(int(spec["min"]), int(spec["max"]))            w_int.setValue(int(default))            return w_int        if t == "float":            w_fp = ScientificDoubleSpinBox()            lo = max(float(spec["min"]), _FLOAT_DEFAULT_MIN)            hi = min(float(spec["max"]), _FLOAT_DEFAULT_MAX)            w_fp.setRange(lo, hi)            d = float(default)            step = max(abs(d) * 0.1, 1.0e-12)            w_fp.setSingleStep(step)            w_fp.setValue(d)            return w_fp        if t == "bool":            w_b = QCheckBox()            w_b.setChecked(bool(default))            return w_b        if t == "enum":            w_e = QComboBox()            for choice in spec["choices"]:                w_e.addItem(str(choice))            idx = list(spec["choices"]).index(default)            w_e.setCurrentIndex(idx)            return w_e        raise ValueError(f"ParamsEditor: unsupported type {t!r}")    def values(self) -> dict[str, Any]:        out: dict[str, Any] = {}        for key, spec in self._schema.items():            w = self._widgets[key]            t = spec["type"]            if t == "int":                out[key] = int(w.value())            elif t == "float":                out[key] = float(w.value())            elif t == "bool":                out[key] = bool(w.isChecked())            elif t == "enum":                out[key] = str(w.currentText())        return out